const toolCall = $json.body?.message?.toolCallList?.[0];

let preferred_date = toolCall?.function?.arguments?.preferred_date || null;
let preferred_time = toolCall?.function?.arguments?.preferred_time || null;

// Add 5 hours if both date and time exist
if (preferred_date && preferred_time) {
  let [hours, minutes] = preferred_time.split(":").map(Number);

  hours += 5;

  // Handle day rollover
  if (hours >= 24) {
    hours -= 24;

    const d = new Date(preferred_date);
    d.setDate(d.getDate() + 1);
    preferred_date = d.toISOString().split("T")[0];
  }

  preferred_time =
    String(hours).padStart(2, "0") +
    ":" +
    String(minutes).padStart(2, "0");
}

return [
  {
    json: {
      preferred_date,
      preferred_time,
      tool_name: toolCall?.function?.name || null,
      tool_call_id: toolCall?.id || null,
    }
  }
];

const toolCall = $json.body?.message?.toolCallList?.[0];
const args = toolCall?.function?.arguments || {};

const full_name = args.full_name || "";
const contact_number = args.contact_number || "";

let date = args.preferred_date;   // e.g. 2026-06-11
let time = args.preferred_time;   // e.g. 15:00

// Split hours and minutes
let [hours, minutes] = time.split(":").map(Number);

// Add 5 hours
hours += 5;

// Handle day rollover
if (hours >= 24) {
  hours -= 24;

  // Increment date by one day
  const d = new Date(date);
  d.setDate(d.getDate() + 1);
  date = d.toISOString().split("T")[0];
}

// Format time
const updatedTime =
  String(hours).padStart(2, "0") +
  ":" +
  String(minutes).padStart(2, "0");

// Build appointment datetime
const appointment_datetime = `${date}T${updatedTime}:00+05:00`;

return [
  {
    json: {
      full_name,
      contact_number,

      preferred_date: date,
      preferred_time: updatedTime,

      appointment_datetime,

      tool_call_id: toolCall?.id || null,
    }
  }
];

