const description = $json.description || "";

// Extract using regex
const nameMatch = description.match(/Name:\s*(.*)/i);
const contactMatch = description.match(/Contact:\s*(.*)/i);

const customer_name = nameMatch ? nameMatch[1].trim() : null;
const customer_number = contactMatch ? contactMatch[1].trim() : null;

return [
  {
    json: {
      customer_name,
      customer_number
    }
  }
];

